#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (s == NULL || out == NULL)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* optional sign */
    int sign = 1;
    if (*s == '+') {
        s++;
    } else if (*s == '-') {
        sign = -1;
        s++;
    }

    if (*s == '\0')
        return 0;

    /* parse digits */
    int32_t acc = 0;
    int32_t const hi = INT32_MAX / 10;
    int32_t const lo = INT32_MAX % 10;

    while (*s != '\0') {
        /* reject trailing non-digit characters (including trailing whitespace) */
        if (!isdigit((unsigned char)*s))
            return 0;

        int digit = *s - '0';

        /* check overflow before multiplying and adding */
        if (acc > hi || (acc == hi && digit > lo)) {
            if (sign == 1)
                return 0;
            /* for negative: INT32_MIN is INT32_MAX+1, so we allow one extra */
            if (acc > hi || (acc == hi && digit > lo + 1))
                return 0;
        }

        acc = acc * 10 + digit;
        s++;
    }

    /* skip trailing whitespace — already rejected non-digit above,
       so we only reach here if the loop ended at '\0' */

    *out = sign * acc;
    return 1;
}

